/**
 * Duck Soup: The Restaurant Game
 * questions_seed.php
 *
 * Replaces questions_seed.php (Phase 1, 157 questions).
 * Seeds all 900 questions from the corrected master dataset.
 *
 * Three corrections applied at generation time:
 *   - Q600 (Hungarian wine "vörös"): duckats_value corrected 40→50 (has 4 answers)
 *   - Q693 (Oregano vs herb): duckats_value corrected 50→40 (missing answer_d)
 *   - Q824 (Beer quote attribution): duckats_value corrected 50→40 (missing answer_d)
 *
 * Usage in setupNewGame():
 *   require_once('questions_seed.php');
 *   DuckSoupQuestions::seedQuestions($this);
 *
 * The previous require_once('questions_seed.php') call should be
 * removed or replaced with this file.
 *
 * card_order is assigned via PHP shuffle() at seed time so each
 * game instance gets a unique randomised draw order.
 * The used column defaults to 0 (never drawn) for all rows.
 *
 * Data columns per row:
 *   (duckats_value, category, question_text,
 *    answer_a, answer_b, answer_c, answer_d,
 *    correct_answer, answer_text)
 *
 * answer_c  = NULL for True/False questions (duckats_value = 30)
 * answer_d  = NULL for True/False and MC3 questions
 * answer_text = NULL where no explanation was provided in source data
 */

class DuckSoupQuestions
{
    /**
     * Seeds the question table for a new game instance.
     * Truncates any existing questions, assigns a fresh shuffled
     * card_order, then bulk-inserts all 900 questions.
