        (50, 'Fruit', 'Cavendish, Valery and Red Jamaica are types of', 'Bananas', 'Grapefruit', 'Melons', 'Plums', 'A', NULL),
        (50, 'Fruit', 'Chayote is a kind of', 'Chili Pepper', 'Flour', 'Fruit', 'Nut', 'C', 'A chayote resembles a large pear and is prepared like a summer squash. It was a main food of the Aztecs and Mayans.'),
